const express = require("express");
const app = express();
app.use(express.json());
const port = 80;
app.listen(port, () => {
  console.log(`App listening on port ${port}...`);
});

const http = require("http").createServer();
const io = require("socket.io")(http);

var db = {}; // a dictionary
db[1] = { // id 1's user details in the database
  name: "abc", 
  score :20,
}; 

// check if name exist in the DB before allowing new user registration 
function isNameUsed(name){

  for (var i of Object.keys(db)) {
    if( db[i].name === name ) return true;
  }
  return false;
  
}

io.on("connection", function (socket) {

  socket.emit("Welcome"); // send welcome message on connection 

  let user_id = 1; 
  let name = ""; 

  socket.on('message',function(message){
  
    console.log(`Client message : ${message}`);

    const [ command , commandInput ] = message.split(" "); 

    if ( isNameUsed(commandInput) ) { // if command input exist in the DB
      socket.emit('err' , 'Username already exists!');
    } else {
      db[user_id] = { name : commandInput }; // update user information on DB

      socket.on('game', function({name,score}){

        console.log(`Client score: ${score}`);
        if( db[1].name !== undefined ){
          io.emit("score",{name , score });  // broadcast player and score 
        } 
      });
    }  
  });
  
  socket.on("disconnect", () => {
    console.log("user disconnected");
  });
});